$ErrorActionPreference = "Stop"\nWrite-Host "=== Protege.Dados 4.0 — Implantação segura ===" -ForegroundColor Cyan\n$repo=Join-Path $HOME "protege-dados-cgu-2026"\n$downloads=Join-Path $HOME "Downloads"\n$zip=Get-ChildItem $downloads -File | Where-Object {$_.Name -like "Protege_Dados_4_0_Ecossistema_Nacional*.zip"} | Sort-Object LastWriteTime -Descending | Select-Object -First 1\nif(-not $zip){throw "Pacote 4.0 não encontrado em Downloads."}\nif(-not (Get-Command git -ErrorAction SilentlyContinue)){throw "Git não está disponível."}\nif(-not (Test-Path (Join-Path $repo ".git"))){git clone "https://github.com/anacarvalheiro-ai/protege-dados-cgu-2026.git" $repo}\nSet-Location $repo\ngit pull origin main\n$temp=Join-Path $env:TEMP "Protege_Dados_4_0"\nif(Test-Path $temp){Remove-Item $temp -Recurse -Force}\nExpand-Archive $zip.FullName $temp -Force\nif(-not (Test-Path ".\web\data\ivpd_uf_v1.json")){throw "Base territorial atual não encontrada; implantação interrompida."}\n$backup=Join-Path $HOME ("Protege_Dados_Backup_"+(Get-Date -Format "yyyyMMdd_HHmmss"))\nNew-Item -ItemType Directory -Path $backup -Force | Out-Null\nCopy-Item ".\web" (Join-Path $backup "web") -Recurse -Force\nWrite-Host "Backup: $backup" -ForegroundColor Green\nCopy-Item (Join-Path $temp "*") $repo -Recurse -Force\n# Validação JSON nativa do PowerShell\nGet-ChildItem ".\web\config\*.json" | ForEach-Object {Get-Content $_.FullName -Raw | ConvertFrom-Json | Out-Null}\nGet-Content ".\web\data\ivpd_uf_v1.json" -Raw | ConvertFrom-Json | Out-Null\nWrite-Host "JSON validado com sucesso." -ForegroundColor Green\ngit status --short\n$resposta=Read-Host "Digite apenas PUBLICAR para enviar ao GitHub"\nif($resposta -cne "PUBLICAR"){Write-Host "Publicação cancelada; arquivos ficaram apenas no computador." -ForegroundColor Yellow; exit 0}\ngit add web src tests docs/4.0 evidence/4.0 scripts .github/workflows requirements-dev.txt pyproject-4.0.toml LEIA-ME-4.0.md\ngit commit -m "Implantar Protege.Dados 4.0 — Ecossistema Nacional"\nif($LASTEXITCODE -eq 1){Write-Host "Nenhuma alteração nova para commit." -ForegroundColor Yellow; exit 0}\nif($LASTEXITCODE -ne 0){throw "Falha no commit."}\ngit push origin main\nif($LASTEXITCODE -ne 0){throw "Falha no push."}\nWrite-Host "PROTEGE.DADOS 4.0 ENVIADO COM SUCESSO." -ForegroundColor Green\n